// New deployment schemas with template support
export const DeployServiceSchema = z.object({
  serverId: z.string(),
  runtime: z.enum(['node']).default('node'), // Changed from template to runtime, focusing on Node.js for now
  repoUrl: z.string(),
  gitAccountId: z.string().optional(),
  repository: z.string().optional(),
  branch: z.string().default('main'),
  appName: z.string(),
  port: z.number().int().min(1000).max(65535).optional(),
  buildCommand: z.string().optional(), // Custom build command, e.g., "npm install && npm run build"
  startCommand: z.string().optional(), // Custom start command, e.g., "npm start" or "node server.js"
  envVars: z.record(z.string(), z.string()).optional(),
  isRedeploy: z.boolean().optional(), // If true, skip port check and use pm2 reload instead of delete+start
});

