export type GetAppsFromDeploymentsInput = z.infer<typeof GetAppsFromDeploymentsSchema>;
export type GetDeploymentByIdInput = z.infer<typeof GetDeploymentByIdSchema>;
export type SetMaxLogLinesInput = z.infer<typeof SetMaxLogLinesSchema>;
export type ManualBuildInput = z.infer<typeof ManualBuildSchema>;
export type ForceFreshDeployInput = z.infer<typeof ForceFreshDeploySchema>;
export type SimpleReloadInput = z.infer<typeof SimpleReloadSchema>;
export type CheckPortAvailabilityInput = z.infer<typeof CheckPortAvailabilitySchema>;
export type OpenExternalURLInput = z.infer<typeof OpenExternalURLSchema>;
export type TemplateDeployInput = z.infer<typeof TemplateDeploySchema>;
export type ListTemplatesInput = z.infer<typeof ListTemplatesSchema>;

// Tunnel schemas
export const TunnelOpenSchema = z.object({
  serverId: z.string(),
  remoteHost: z.string().default('127.0.0.1'),
  remotePort: z.number(),
  /** Local port to bind. Use 0 or omit to auto-assign an available port. */
  localPort: z.number().default(0),
});
export type TunnelOpenInput = z.infer<typeof TunnelOpenSchema>;

export const TunnelCloseSchema = z.object({
  serverId: z.string(),
  localPort: z.number(),
});
export type TunnelCloseInput = z.infer<typeof TunnelCloseSchema>;

export const TunnelStatusSchema = z.object({
  serverId: z.string(),
});
export type TunnelStatusInput = z.infer<typeof TunnelStatusSchema>;

// Environment (staging/preview) schemas
export const EnvironmentTypeSchema = z.enum([
  'production',
  'staging',
  'preview',
  'alpha',
  'beta',
  'qa',
  'demo',
  'development',
  'test',
]);
export type EnvironmentType = z.infer<typeof EnvironmentTypeSchema>;

export const NonProductionEnvironmentTypeSchema = z.enum([
  'staging',
  'preview',
  'alpha',
  'beta',
  'qa',
  'demo',
  'development',
  'test',
]);
export type NonProductionEnvironmentType = z.infer<typeof NonProductionEnvironmentTypeSchema>;

export const CreateEnvironmentSchema = z.object({
  serverId: z.string(),
  productionStackId: z.string(),
  environmentType: NonProductionEnvironmentTypeSchema,
  environmentName: z.string().min(1).max(50).regex(/^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/, {
    message: 'Name must be lowercase alphanumeric with hyphens, starting and ending with alphanumeric',
  }),
  subdomainPrefix: z.string().min(1).max(50).optional(),
  customDomain: z.string().optional(),
  branchName: z.string().optional(),
  buildLocation: z.enum(['vps', 'github-actions']).optional(),
  copyEnvVars: z.boolean().optional().default(true),
  customEnvVars: z.record(z.string(), z.string()).optional(),
  hostPort: z.number().int().min(1).max(65535).optional(),
});
export type CreateEnvironmentInput = z.infer<typeof CreateEnvironmentSchema>;

export const ListEnvironmentsSchema = z.object({
  serverId: z.string(),
  productionStackId: z.string(),
});
export type ListEnvironmentsInput = z.infer<typeof ListEnvironmentsSchema>;

export const DeleteEnvironmentSchema = z.object({
  serverId: z.string(),
  stackId: z.string(),
});
export type DeleteEnvironmentInput = z.infer<typeof DeleteEnvironmentSchema>;

export const PromoteEnvironmentSchema = z.object({
  serverId: z.string(),
  stagingStackId: z.string(),
  deploymentStrategy: z.enum(['standard', 'zero_downtime']).optional().default('zero_downtime'),
  keepStaging: z.boolean().optional().default(false),
  createBackup: z.boolean().optional().default(true),
});
export type PromoteEnvironmentInput = z.infer<typeof PromoteEnvironmentSchema>;

export const UpdateEnvironmentSettingsSchema = z.object({
  serverId: z.string(),
  stackId: z.string(),
  autoDeployRules: z.array(z.object({
    branchPattern: z.string(),
    environmentType: NonProductionEnvironmentTypeSchema,
    autoCreate: z.boolean(),
  })).optional(),
  previewUrlPattern: z.string().optional(),
});
export type UpdateEnvironmentSettingsInput = z.infer<typeof UpdateEnvironmentSettingsSchema>;

export const DeployBranchSchema = z.object({
  serverId: z.string(),
  productionStackId: z.string(),
  branchName: z.string().min(1),
  environmentType: NonProductionEnvironmentTypeSchema.optional().default('preview'),
});
export type DeployBranchInput = z.infer<typeof DeployBranchSchema>;

export const ReconcileEnvironmentsSchema = z.object({
  serverId: z.string(),
  productionStackId: z.string(),
});
export type ReconcileEnvironmentsInput = z.infer<typeof ReconcileEnvironmentsSchema>;

export const CleanupExpiredEnvironmentsSchema = z.object({
  serverId: z.string(),
});
export type CleanupExpiredEnvironmentsInput = z.infer<typeof CleanupExpiredEnvironmentsSchema>;
